// ── TANK THRESHOLD CONSTANTS ─────────────────────────────────
// Single source of truth — used by dashboard, tanks page, and notifications
// FIX: Previously 25% on dashboard vs 20% on tanks/notifications (bug F-05)
const TANK_CRITICAL_PCT  = 10;  // 🔴 Critical — immediate refill needed
const TANK_LOW_PCT       = 20;  // 🟠 Low — alert threshold (notifications fire here)
const TANK_MEDIUM_PCT    = 40;  // 🟡 Medium — monitor closely

// Data snapshot max-age before stale warning is shown (24 hours in ms)
// FIX: Previously no age check on offline snapshot (bug F-04)
const SNAPSHOT_STALE_MS  = 24 * 60 * 60 * 1000;  // 24 hours

// ── FORMATTERS ───────────────────────────────────────────────
const fmt = n => new Intl.NumberFormat('en-IN', { maximumFractionDigits: 2 }).format(n);
const cur = n => '₹' + fmt(n);
// BUG-11 FIX: Was using new Date().getFullYear/Month/Date() which reads the BROWSER's local timezone.
// If the device is set to UTC (common on some tablets), the date is wrong after 18:30 IST.
// Use the same IST-pinned approach as the server's istDate() function.
const today = () =>
  new Date().toLocaleString('en-CA', { timeZone: 'Asia/Kolkata' }).slice(0, 10);
const now = () => new Date().toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', hour12: false });

// ── SECURITY UTILITIES ──────────────────────────────────────
// XSS Sanitizer — use on ALL user-entered data before rendering
function sanitize(str) {
  if (str === null || str === undefined) return '';
  if (typeof str !== 'string') return String(str);
  return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
            .replace(/"/g,'&quot;').replace(/'/g,'&#x27;');
}

// SHA-256 hash using Web Crypto API
async function hashPassword(password) {
  const encoder = new TextEncoder();
  const data = encoder.encode(password);
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
}

// Synchronous hash fallback for initial load (simple djb2 + hex)
function hashSync(str) {
  let h = 5381;
  for (let i = 0; i < str.length; i++) h = ((h << 5) + h) + str.charCodeAt(i);
  return (h >>> 0).toString(16).padStart(8,'0');
}

// App Secret for session signing
function getAppSecret() {
  let secret = localStorage.getItem('fb_app_secret');
  if (!secret) {
    const arr = new Uint8Array(32);
    crypto.getRandomValues(arr);
    secret = Array.from(arr).map(b => b.toString(16).padStart(2,'0')).join('');
    localStorage.setItem('fb_app_secret', secret);
  }
  return secret;
}

// Session signing — synchronous djb2 (sufficient for localStorage tamper-detection;
// full crypto protection handled server-side via JWT sessions)
function signData(payload) {
  const raw = JSON.stringify(payload);
  const sig = hashSync(raw + getAppSecret());
  return JSON.stringify({ payload: raw, sig });
}
function verifyData(stored) {
  try {
    const { payload, sig } = JSON.parse(stored);
    const expected = hashSync(payload + getAppSecret());
    if (sig !== expected) return null;
    return JSON.parse(payload);
  } catch { return null; }
}

// Rate Limiting
// BUG-03 FIX: Counters are now persisted in sessionStorage so a page reload does not
// reset them. sessionStorage is scoped to the browser tab and is cleared when the tab
// is closed — making a silent counter-reset much harder than deleting a localStorage key.
const _RL_SS_KEY = 'fb_login_rl';
const MAX_LOGIN_ATTEMPTS = 5;
const LOCKOUT_MS = 5 * 60 * 1000; // 5 minutes

function _rlLoad() {
  try { return JSON.parse(sessionStorage.getItem(_RL_SS_KEY) || '{}'); } catch { return {}; }
}
function _rlSave(data) {
  try { sessionStorage.setItem(_RL_SS_KEY, JSON.stringify(data)); } catch {}
}

function checkRateLimit(key) {
  const attempts = _rlLoad();
  const r = attempts[key];
  if (!r) return true;
  if (r.lockedUntil && Date.now() < r.lockedUntil) {
    const sec = Math.ceil((r.lockedUntil - Date.now()) / 1000);
    toast('Account locked. Try again in ' + sec + 's', 'error');
    return false;
  }
  if (r.lockedUntil && Date.now() >= r.lockedUntil) {
    delete attempts[key];
    _rlSave(attempts);
    return true;
  }
  return r.count < MAX_LOGIN_ATTEMPTS;
}
function recordFailedLogin(key) {
  const attempts = _rlLoad();
  if (!attempts[key]) attempts[key] = { count: 0 };
  attempts[key].count++;
  if (attempts[key].count >= MAX_LOGIN_ATTEMPTS) {
    attempts[key].lockedUntil = Date.now() + LOCKOUT_MS;
    toast('Too many failed attempts. Locked for 5 minutes.', 'error');
  }
  _rlSave(attempts);
}
function recordSuccessLogin(key) {
  const attempts = _rlLoad();
  delete attempts[key];
  _rlSave(attempts);
}

// Audit Log
function auditLog(action, details) {
  const entry = {
    id: Date.now() + '_' + Math.random().toString(36).substr(2, 6),
    timestamp: new Date().toISOString(),
    user: (typeof APP !== 'undefined' && APP && APP.role === 'admin')
      ? (APP.adminUser?.name || 'Admin')
      : (empState?.user?.name || 'Employee'),
    role: (typeof APP !== 'undefined' && APP ? APP.role : null) || 'unknown',
    action: action,
    details: details || {},
  };
  if (typeof APP !== 'undefined' && APP) { if (!APP.auditLog) APP.auditLog = []; APP.auditLog.unshift(entry); }
  // Non-blocking DB write with timeout
  if (db && db.db) {
    Promise.race([
      db.add('auditLog', entry),
      new Promise((_, rej) => setTimeout(() => rej('timeout'), 2000))
    ]).catch(() => {});
  }
}

// Schema validators
function validateSessionShape(data) {
  if (!data || typeof data !== 'object') return false;
  if (typeof data.loggedIn !== 'boolean') return false;
  if (!['admin', 'employee', null].includes(data.role)) return false;
  if (data.loggedIn && !data.timestamp) return false;
  return true;
}
function validateEmpSessionShape(data) {
  if (!data || typeof data !== 'object') return false;
  if (typeof data.active !== 'boolean') return false;
  if (data.active && (!data.user || typeof data.user.id !== 'number')) return false;
  if (typeof data.openReadings !== 'object') return false;
  if (!Array.isArray(data.sales)) return false;
  // Ensure arrays/objects have correct types if present
  if (data.closeReadings !== undefined && typeof data.closeReadings !== 'object') return false;
  if (data.dipReadings !== undefined && !Array.isArray(data.dipReadings)) return false;
  // Coerce page to string if missing
  if (!data.page || typeof data.page !== 'string') data.page = 'readings';
  return true;
}

// Input validators
function validateSaleInput(fuelType, liters, amount, vehicle, prices, mode) {
  const errors = [];
  if (!fuelType || !['petrol','diesel','premium','premium_petrol'].includes(fuelType))
    errors.push('Invalid fuel type');
  if (isNaN(liters) || liters <= 0)
    errors.push('Liters must be positive');
  // No upper liter limit — allow bulk/tanker sales
  if (isNaN(amount) || amount <= 0)
    errors.push('Amount must be positive');
  if (amount > 10000000)
    errors.push('Amount exceeds ₹1,00,00,000 limit');
  const price = prices?.[fuelType] || 0;
  if (price > 0 && liters > 0) {
    const expected = liters * price;
    const tolerance = Math.max(1, expected * 0.01); // 1% tolerance or ₹1 min
    if (Math.abs(amount - expected) > tolerance)
      errors.push('Amount mismatch with rate. Expected ≈₹' + expected.toFixed(2));
  }
  // Vehicle number required for credit/UPI/card; optional for cash walk-ins
  if (mode !== 'cash') {
    if (!vehicle || vehicle.length < 2)
      errors.push('Enter valid vehicle number');
  }
  if (vehicle && vehicle.length > 0 && !/^[A-Z0-9\s\-\.]+$/i.test(vehicle))
    errors.push('Vehicle number has invalid characters');
  return errors;
}
function validateReading(opening, closing) {
  if (isNaN(closing) || closing < 0) return 'Invalid reading';
  if (opening !== undefined && closing < opening)
    return 'Closing reading cannot be less than opening';
  if (closing - (opening || 0) > 10000)
    return 'Reading difference too large (>10000L). Verify.';
  return null;
}
function validateExpenseInput(amount, category, desc) {
  const errors = [];
  if (isNaN(amount) || amount <= 0) errors.push('Amount must be positive');
  if (amount > 500000) errors.push('Amount exceeds ₹5,00,000 limit');
  if (!category) errors.push('Select category');
  if (!desc || desc.trim().length < 3) errors.push('Enter description (min 3 chars)');
  return errors;
}

// Session expiry constants
const SESSION_MAX_AGE     = 30 * 24 * 60 * 60 * 1000; // 30 days
const SESSION_IDLE_TIMEOUT = 15 * 60 * 1000;           // 15 minutes inactivity
let idleTimer = null;

// ── Explicit logout marker ───────────────────────────────────────────────────
// Written by appLogout() so loadSession() can reject a session that was
// explicitly ended, even if fb_session was somehow re-written before reopen.
function markExplicitLogout() {
  try { localStorage.setItem('fb_explicit_logout', '1'); } catch(e) {}
}
function clearExplicitLogout() {
  try { localStorage.removeItem('fb_explicit_logout'); } catch(e) {}
}

// ── Browser/tab close: clear session immediately ─────────────────────────────
// pagehide fires on tab close, window close, and navigation away from the page.
// It is more reliable than beforeunload in mobile browsers and PWAs.
// Clearing fb_session here means reopening the app always requires re-login,
// regardless of how much time has passed or what the idle timeout is set to.
if (typeof window !== 'undefined') {
  window.addEventListener('pagehide', function() {
    try { localStorage.removeItem('fb_session'); } catch(e) {}
  });
}

function resetIdleTimer() {
  clearTimeout(idleTimer);
  // Update lastActive in session
  const raw = localStorage.getItem('fb_session');
  if (raw) {
    const data = verifyData(raw);
    if (data) {
      data.lastActive = Date.now();
      localStorage.setItem('fb_session', signData(data));
    }
  }
  idleTimer = setTimeout(() => {
    if (APP.loggedIn) {
      toast('Session expired due to inactivity', 'info');
      appLogout();
    }
  }, SESSION_IDLE_TIMEOUT);
}

// Backup reminder
function checkBackupReminder() {
  const lastBackup = localStorage.getItem('fb_last_backup');
  let daysSince;
  if (lastBackup) {
    daysSince = Math.floor((Date.now() - parseInt(lastBackup)) / 86400000);
  } else {
    // No backup ever done — use station creation date as reference so brand-new
    // stations don't immediately show "999 days". Fall back to 0 if no creation date.
    const tenantCreatedAt = APP.tenant?.createdAt || APP.tenant?.created_at || null;
    const refTime = tenantCreatedAt ? new Date(tenantCreatedAt).getTime() : Date.now();
    daysSince = Math.floor((Date.now() - refTime) / 86400000);
  }
  if (daysSince >= 7 && APP.role === 'admin') {
    setTimeout(() => toast('You haven\'t backed up data in ' + daysSince + ' days. Go to Settings → Export.', 'info'), 3000);
  }
}

