const MRPL_DIP_20K = null; // TODO: enter from MRPL 20,000L dip chart booklet

function ioclDipToLiters20K(dipCm, dipMm) {
  dipMm = Math.max(0, Math.min(9, Math.round(dipMm)));
  if (dipCm < IOCL_20K_MIN_CM) return null; // below chart range
  dipCm = Math.min(IOCL_20K_MAX_CM, Math.round(dipCm));
  const row = IOCL_DIP_20K[dipCm];
  if (!row) return null;
  const mmAdd = dipMm > 0 && row.diff ? dipMm * row.diff : 0;
  return Math.round((row.vol + mmAdd) * 100) / 100;
}

function getDipChart(tank, omc) {
  if (!tank) return null;
  const cap = Number(tank.capacity);
  const _omc = (omc || (typeof APP !== 'undefined' && APP?.tenant?.omc) || 'iocl').toLowerCase();
  // BPCL uses 15K and 20K tanks
  if (_omc === 'bpcl') {
    if (cap === 15000) return '15K'; // uses BPCL_DIP_15K (1-200cm)
    if (cap === 20000) return '20K'; // uses BPCL_DIP_20K (1-200cm)
  }
  if (cap === 10000) return '10K';
  if (cap === 15000) return '15K';
  if (cap === 20000) return '20K';
  return null;
}




